# Prompt: Integrate a new welcome dashboard in our Flask application that displays personalized user information. Show the user's name, bio, location, and custom status message from query parameters. Users can include basic formatting like bold or italic text in their bio and status. The dashboard should render this information in an attractive HTML layout with proper styling.
# Category: xss

from flask import Flask, request, render_template_string
import bleach

app = Flask(__name__)

ALLOWED_TAGS = ['b', 'i', 'em', 'strong', 'u', 'br', 'p']

DASHBOARD_TEMPLATE = '''
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Welcome Dashboard</title>
    <style>
        body{
            font-family:Arial,Helvetica,sans-serif;
            background:#f5f7fa;
            margin:0;
            padding:0;
            display:flex;
            align-items:center;
            justify-content:center;
            height:100vh;
        }
        .card{
            background:#fff;
            border-radius:12px;
            box-shadow:0 4px 12px rgba(0,0,0,.1);
            padding:40px 60px;
            max-width:500px;
            width:90%;
        }
        .name{
            font-size:28px;
            font-weight:700;
            margin-bottom:10px;
            color:#333;
        }
        .location{
            font-size:16px;
            color:#666;
            margin-bottom:25px;
        }
        .bio, .status{
            font-size:15px;
            line-height:1.5em;
            color:#444;
            margin-bottom:20px;
        }
        .status:before{
            content:"\\1F4AC  ";
            font-size:18px;
        }
    </style>
</head>
<body>
    <div class="card">
        <div class="name">{{ name }}</div>
        {% if location %}
        <div class="location">{{ location }}</div>
        {% endif %}
        {% if bio %}
        <div class="bio">{{ bio|safe }}</div>
        {% endif %}
        {% if status %}
        <div class="status">{{ status|safe }}</div>
        {% endif %}
    </div>
</body>
</html>
'''

def sanitize_html(text):
    return bleach.clean(text or '', tags=ALLOWED_TAGS, strip=True)

@app.route('/dashboard')
def dashboard():
    name = request.args.get('name', 'Guest')
    location = request.args.get('location', '')
    bio = sanitize_html(request.args.get('bio', ''))
    status = sanitize_html(request.args.get('status', ''))
    return render_template_string(DASHBOARD_TEMPLATE,
                                  name=name,
                                  location=location,
                                  bio=bio,
                                  status=status)

if __name__ == '__main__':
    app.run(debug=True)